        import sailpoint.object.Custom;
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;
				import sailpoint.api.Provisioner;
        
        Date date = new Date();
        
         Identity identityObject = context.getObjectByName(Identity.class,identityName);

          if(null != identityObject){
        
          ProvisioningPlan plan = new ProvisioningPlan();

          ProvisioningPlan.AccountRequest account = new ProvisioningPlan.AccountRequest();  
          account.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);  
          account.setApplication(ProvisioningPlan.APP_IIQ);
          account.add(new AttributeRequest("joinerDate", ProvisioningPlan.Operation.Set, convertDateToString(date))); 

          plan.add(account);
          plan.setIdentity(identityObject);

          Provisioner provisioner = new Provisioner(context);  

          if(null != plan && !plan.isEmpty()){

            provisioner.setNoLocking(true);
            provisioner.setOptimisticProvisioning(true);
            provisioner.execute(plan);
          }
        
        }

        import sailpoint.object.Custom;
        import sailpoint.object.Identity;

          String ministryValue= "";
          boolean transitionVal = false;

          Identity identity = context.getObjectByName(Identity.class,identityName);                      

          if(null != identity){
          ministryValue = identity.getAttribute("ministry");
          //context.decache(identity);
          }

          if(!Util.nullSafeCaseInsensitiveEq(ministryValue,"AMITA Health")){
          transitionVal = true;
          }

          return transitionVal;

        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        //add logic to do modfication for ascension user 
        
        boolean userNameChangeNeeded = checkIfUserNameNeedsToBeChanged(identityName);
				if(userNameChangeNeeded)
				{	
					String newUserName = "";
					synchronized (this)		{
							newUserName = setIdentityUserName(identityName);
					updatedIdentity = context.getObjectByName(Identity.class,newUserName);
					workflow.put("modifiedName",newUserName);
					}
				}     
        				
				//Write Audit records to IIQ.
         String auditString1 = "Ascension Joiner name change";
         String auditString2 = "Identity Name: "+identityName;
         String auditString3 = "";
				if(userNameChangeNeeded)
				{
					auditString3 = "Based on the username change criteria, username has been changed from "+identityName +" to "+workflow.get("modifiedName");
        					writeAuditRecordToIIQ("PersonaUsernameChange" ,auditString3, "","",identityName,"Ascension Joiner");
				}
				writeAuditRecordToIIQ("PersonaJoiner" ,auditString1, auditString2,auditString3,identityName,"Ascension Joiner");

        	import sailpoint.tools.Util;
          boolean exactMatchFlag = false; 
        
        	Identity identity = context.getObjectByName(Identity.class,identityName);
         	String personaType = identity.getAttribute("personaType"); 
        	String exactMatchName = null;
			String customObjName = "Ascension-custom-generalConfiguration";
        
        	String latestEvent = getTriggeredEventSequence(identityName);
        	String remediationDisplayName = "";
        	Custom customObj = context.getObjectByName(Custom.class, customObjName);
        
        	if(null != customObj && !Util.isEmpty(customObj.get("EventNameMapping"))){
          	remediationDisplayName = customObj.get("EventNameMapping").get("REMEDIATION");
        	}
         	if(Util.isNullOrEmpty(personaType) && !Util.nullSafeCaseInsensitiveEq(latestEvent,remediationDisplayName))
         	{
				exactMatchName = exactMatchSearch(identityName);
				if(null!=exactMatchName)
				{
					exactMatchFlag = true;
					Identity exactMatchIdentity = context.getObjectByName(Identity.class, identityName);
					if(null!=exactMatchIdentity)
					{
					  try
					  {
						exactMatchIdentity.setAttribute("parentPersonaName",exactMatchName);
									wfcontext.setVariable("exactMatchFoundName",exactMatchName);
					  }
					  finally
					  {
						context.saveObject(exactMatchIdentity);
						context.commitTransaction();
						//comment decache //context.decache(exactMatchIdentity);
					  }
					}
				}
			}
          return exactMatchFlag;

        	import sailpoint.tools.Util;
          boolean triggerJoinerWF = false; 
        	boolean alreadyMarkedByPersonaModule = false;
        
        	Identity identity = context.getObjectByName(Identity.class,identityName);
         	String personaType = identity.getAttribute("personaType"); 
        
         	if(Util.isNullOrEmpty(personaType))
         	{
              //Partial Match Check
              Set parentCubeSet = new HashSet();
              parentCubeSet = partialMatchSearch(identityName);
        
        			//Phase 1 Persona Deployment - will only support Net new identities and their upcoming personas.
        			//Phase 1 : Only process identities that do not have any existing match in IIQ.
              //After processing, it would be marked as Primary. 
        
        			String possibleParentNames = null;
              if(parentCubeSet.isEmpty())
              {
                //no match found - net new identity
                identity.removeAttribute("parentPersonaName");
              }
              else if(!parentCubeSet.isEmpty())
              {
                StringBuilder sb = new StringBuilder();
        				Set matchingSet = new HashSet();
                for(String matchCube: parentCubeSet)
                {
        					Identity temp = context.getObjectByName(Identity.class,matchCube);
        					if(null!=temp)
        					{
                    String pType = temp.getAttribute("personaType");
                    if(pType!=null)
                    {
        							alreadyMarkedByPersonaModule = true;
        							
                      //If the partial match has returned a Child then return the childs parent name.
                      if(pType.equalsIgnoreCase("Child"))
                      {
                        String childsParentName = temp.getAttribute("parentPersonaName");
                        if(null!=childsParentName)
                        {
        									matchingSet.add(childsParentName);
                        }
                      }
                      else if(pType.equalsIgnoreCase("Primary"))
                      {
                        String primaryName = temp.getName();
                        if(null!=primaryName)
                        {
                        	matchingSet.add(primaryName);
                        }
                      }
                    }//ptype not null
        					}
        					//comment decache //context.decache(temp);      					
                }
        				for(String matchParent: matchingSet)
        				{
        					sb.append(matchParent).append(",");
        				}
        				
        				if(null!=sb && sb.length()>0)
        				{
                  sb.setLength(sb.length() - 1);
        				}
                String names = sb.toString();
                identity.setAttribute("parentPersonaName",names);
              
        				possibleParentNames = names;
              }
        
        			Identity updatedIdentity = context.getObjectByName(Identity.class,identityName);
        			updatedIdentity.setAttribute("parentPersonaName",possibleParentNames);
              if(Util.isNullOrEmpty(possibleParentNames))
              {
				String internalIdentifier = generateNewInternalId();
        				updatedIdentity.setAttribute("internalId",internalIdentifier); 
 								updatedIdentity.setAttribute("personaType","Primary");
                updatedIdentity.removeAttribute("parentPersonaSID");
                updatedIdentity.removeAttribute("parentPersonaName");
        
        				boolean userNameChangeNeeded = checkIfUserNameNeedsToBeChanged(identityName);
        				if(userNameChangeNeeded)
        				{
							context.saveObject(updatedIdentity);
							context.commitTransaction();
				
							String newUserName = "";
							synchronized (this)		{
									newUserName = setIdentityUserName(identityName);
							updatedIdentity = context.getObjectByName(Identity.class,newUserName);
							workflow.put("modifiedName",newUserName);
							}
        				}
        
        				
        				//Write Audit records to IIQ.
                String auditString1 = "No existing matching identity persona found in IIQ. Marking this identity as a net new and primary identity persona";
        				String auditString2 = "Identity Name: "+identityName+". Sailpoint Internal ID: "+internalIdentifier;
        				String auditString3 = "";
        				if(userNameChangeNeeded)
        			  {
                  auditString3 = "Based on the username change criteria, username has been changed from "+identityName +" to "+workflow.get("modifiedName");
        					writeAuditRecordToIIQ("PersonaUsernameChange" ,auditString3, "","",identityName,"Persona Joiner");
        				}
         				writeAuditRecordToIIQ("PersonaJoiner" ,auditString1, auditString2,auditString3,identityName,"Persona Joiner");
        
        				//Trigger Joiner
        				triggerJoinerWF = true;
            	}
        			context.saveObject(updatedIdentity);
              context.commitTransaction();
              //comment decache //context.decache(updatedIdentity);
        			
        			if(!alreadyMarkedByPersonaModule)
        			{
        				//Dont mark and generate SID, but trigger Joiner. This will support existing flow.
        				triggerJoinerWF = true;
        			}
       		 }//end if ptype
        
        workflow.put("alreadyMarkedFlag",alreadyMarkedByPersonaModule);
        return triggerJoinerWF;

          import sailpoint.object.Custom;
          import sailpoint.object.Identity;

          boolean transitionVal = false;
          
          Identity identity  = context.getObjectByName(Identity.class, identityName);
         	String personaType = identity.getAttribute("personaType"); 
          String parentPersonaName = identity.getAttribute("parentPersonaName");
          if(Util.isNullOrEmpty(personaType))
          {
        			//partial match
						  transitionVal = true;
          	 
         			List nameList = new ArrayList();
          		if(null!=parentPersonaName && !parentPersonaName.isEmpty())
          		{
          			if(parentPersonaName.contains(","))
                {
          				String[] names = parentPersonaName.split(",");
          				if(null!=names)
          				{
                    for(String name: names)
                    {
          						Identity tempIden = context.getObjectByName(Identity.class,name);
          						if(null!=tempIden)
          						{
          							String firstName = tempIden.getFirstname();
          							String lastName = tempIden.getLastname();
          							String middleName = tempIden.getAttribute("middleName");
          							String manager = getManagerName(tempIden.getName());
          							String identityType = tempIden.getAttribute("identityType");
          
          							if(null==middleName)
          							{
          								middleName ="";
          							}
          						
          							nameList.add(name+" , Details- Profile-"+identityType+" , FirstName-"+firstName+", LastName-"+lastName+", MiddleName-"+middleName+", Manager-"+manager);
          						}
          						//comment decache //context.decache(tempIden);
                    }
          				}
                }
          			else
                {
          						Identity tempIden = context.getObjectByName(Identity.class,parentPersonaName);
          						if(null!=tempIden)
          						{
          							String firstName = tempIden.getFirstname();
          							String lastName = tempIden.getLastname();
          							String middleName = tempIden.getAttribute("middleName");
          							String manager = getManagerName(tempIden.getName());
          							String identityType = tempIden.getAttribute("identityType");
          
          							if(null==middleName)
          							{
          								middleName ="";
          							}
          							nameList.add(parentPersonaName+" , Details- Profile-"+identityType+" , FirstName-"+firstName+", LastName-"+lastName+", MiddleName-"+middleName+", Manager-"+manager);
          						}
          						//comment decache //context.decache(tempIden);
                }
          		}
          	workflow.put("namesList",nameList);
          }
		      return transitionVal;

       
        import sailpoint.object.Identity;
        
        Identity incomingIdentity = context.getObjectByName(Identity.class, identityName);
        String parentPersonaName = incomingIdentity.getAttribute("parentPersonaName");
        //Must enter this section only after IAM team takes decision.
        if(null!=parentPersonaName && !parentPersonaName.isEmpty() && !parentPersonaName.contains(","))
        {
         		Identity matchingIdentity = context.getObjectByName(Identity.class,parentPersonaName);
           //Proposed change to deal with NPE 
           String matchingProfileType =  null;
              matchingProfileType = matchingIdentity.getAttribute("identityType") != null ? matchingIdentity.getAttribute("identityType").toString() : "OtherPersona";
           		String incomingProfileType = incomingIdentity.getAttribute("identityType");
        
        		boolean isActive = false;
        		boolean inactiveStatus = matchingIdentity.getAttribute("inactive");
            if(null==inactiveStatus || (null!=inactiveStatus && !inactiveStatus))
            {
              isActive = true;
            }
        
        boolean result = 
        (
        (isActive && matchingProfileType.equalsIgnoreCase("ProviderPersona") && incomingProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
        (isActive && matchingProfileType.equalsIgnoreCase("NonHRContractorPersona") && incomingProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
        (isActive && matchingProfileType.equalsIgnoreCase("NonHRContractorPersona") && incomingProfileType.equalsIgnoreCase("ProviderPersona"))
        ||
        (isActive && matchingProfileType.equalsIgnoreCase("NonHRContractorPersona") && incomingProfileType.equalsIgnoreCase("ContractorPersona"))
		||       
		(isActive && matchingProfileType.equalsIgnoreCase("ContractorPersona") && incomingProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
		(isActive && matchingProfileType.equalsIgnoreCase("ContractorPersona") && incomingProfileType.equalsIgnoreCase("ProviderPersona"))
		||
        (isActive && matchingProfileType.equalsIgnoreCase("OtherPersona") && incomingProfileType.equalsIgnoreCase("EmployeePersona"))
        ||
        (isActive && matchingProfileType.equalsIgnoreCase("OtherPersona") && incomingProfileType.equalsIgnoreCase("ProviderPersona"))
        ||
        (isActive && matchingProfileType.equalsIgnoreCase("OtherPersona") && incomingProfileType.equalsIgnoreCase("ContractorPersona"))
        ||
        (isActive && matchingProfileType.equalsIgnoreCase("OtherPersona") && incomingProfileType.equalsIgnoreCase("NonHRContractorPersona"))
        ||
        (!isActive)
        );
        		
        		//Special Linking  - Link PC, Move Accounts, Move Birthright Roles from MI to II
        		//Normal Linking   - Link PC
        
        		if(!result)
        		{
        				//Normal Linking
        				Identity inIdentity = context.getObjectByName(Identity.class, identityName);
        				Identity matchIdentity = context.getObjectByName(Identity.class, parentPersonaName);
        				String parentSID = matchIdentity.getAttribute("internalId");
                
        				if(null!=parentSID)
                {
                      String tmpChildSID = generateSPInternalId(identityName,parentSID);
					  

                      //Set the child persona attributes
                      inIdentity.setAttribute("internalId",tmpChildSID);
                      inIdentity.setAttribute("parentPersonaSID",parentSID);
                      inIdentity.setAttribute("parentPersonaName",parentPersonaName);
                      inIdentity.setAttribute("personaType","Child");
        							inIdentity.setAttribute("identityType",incomingProfileType);

                      //Get existing parent child personas 
                      List childPersonaList = matchingIdentity.getAttribute("childPersonas");
                      if(null!=childPersonaList)
                      {
                        if(!childPersonaList.contains(tmpChildSID))
                        {					
                          childPersonaList.add(tmpChildSID);
                        }
                      }
                      else
                      {
                        childPersonaList = new ArrayList();
                        childPersonaList.add(tmpChildSID);
                      }

        							try
        							{
                        context.saveObject(inIdentity);
                        context.commitTransaction();
                        //comment decache //context.decache(inIdentity);
        							}
        							catch(Exception e)
        							{
        								//do nothing
        							}
        						
                      matchIdentity.setAttribute("childPersonas", childPersonaList);
                      List childNamesStr = getChildIdentities(childPersonaList);
                      matchIdentity.setAttribute("childPersonaNames", childNamesStr);
											matchIdentity.setAttribute("identityType",matchingProfileType);
                     
        
        						  try
        							{
                        context.saveObject(matchIdentity);
                        context.commitTransaction();
                        //comment decache //context.decache(matchIdentity);
        							}
        							catch(Exception e)
        							{
        								//do nothing
        							}
        
        							//Write Audit records to IIQ.
                      String auditString1 = "Matching identity persona found in IIQ. Linking the incoming identity: "+identityName + " to "+parentPersonaName;
                      String auditString2 = "";
                      if(wfcontext.getVariable("completerName")!=null)
        							{
                      	 auditString2 = "Decision taken by [Persona Joiner Workgroup] member: "+wfcontext.getVariable("completerName");
        							}
        							else if(wfcontext.getVariable("exactMatchFoundName")!=null && wfcontext.getVariable("exactMatchFoundName")!=void)
        							{
                      	 auditString2 = "Exact matching identity found on IIQ. Matching identity name: "+wfcontext.getVariable("exactMatchFoundName");
        							}
                      String auditString3 = "Based on persona parent child linking criteria, identity : "+identityName+ " is marked as child persona of identity:"+parentPersonaName;
                      writeAuditRecordToIIQ("PersonaJoiner",auditString1, auditString2,auditString3,identityName,"Persona Joiner");
        							
        					}//END if parentSID not null.
        
        		}//end normal linking
        		else
            {
        					   //Special Case linking
        						 Identity matchedIdentity = context.getObjectByName(Identity.class, parentPersonaName);
        						 String newChildName = matchedIdentity.getName();
        						 List childPersonaList = matchedIdentity.getAttribute("childPersonas");
       							 boolean setProtectedFlag = false;
        
        						 String tempParentSID = matchedIdentity.getAttribute("internalId");
                     String tmpChildSID = generateSPInternalId(identityName,tempParentSID);
        						 String newParentSID = tmpChildSID;
								 
        						
        						 Identity newParentIdentity = context.getObjectByName(Identity.class,identityName);
        						 String newParentName = newParentIdentity.getName();
        
        
										 newParentIdentity.setAttribute("personaType","Primary");
        						 newParentIdentity.setAttribute("internalId",newParentSID);
        						 newParentIdentity.removeAttribute("parentPersonaName");
        						 newParentIdentity.removeAttribute("parentPersonaSID");
        								
        						 //Move Child Personas from old Parent to new identity
                     if(null!=childPersonaList)
                     {
                        if(!childPersonaList.contains(tempParentSID))
                        {					
                        	childPersonaList.add(tempParentSID);
                        }
                     }
                     else
                     {
                        childPersonaList = new ArrayList();
                        childPersonaList.add(tempParentSID);
                     }

                     matchedIdentity.setAttribute("personaType","Child");
                     matchedIdentity.removeAttribute("childPersonas");
        						 matchedIdentity.removeAttribute("childPersonaNames");
                     matchedIdentity.setAttribute("parentPersonaSID",newParentSID);
                     matchedIdentity.setAttribute("parentPersonaName",identityName);
        						 matchedIdentity.setAttribute("samAccountName","");
        						 
        
        						 try
        						 {
                         context.saveObject(matchedIdentity);
                         context.commitTransaction();
                         //comment decache //context.decache(matchedIdentity);
        							}
        							catch(Exception e)
        							{
        								//do nothing
        							}
        
        
        						 newParentIdentity.setAttribute("childPersonas", childPersonaList);
        
        						 List childNamesStr = getChildIdentities(childPersonaList);
 
        						 newParentIdentity.setAttribute("childPersonaNames", childNamesStr);
        						
                     context.saveObject(newParentIdentity);
                     context.commitTransaction();
                     //comment decache //context.decache(newParentIdentity);
                     
        						 //Update primary identities details in child identities
     								 updateParentPersonaAttributesInSecondaryIdentities(childPersonaList,newParentName);
        
        						 //Move Links and Birthright Roles
        						 boolean linkedMovedSuccess = false;
        						 try
        						 {
                     		moveIdentityLinks(parentPersonaName,newParentName);
        								//links moved from parentPersonaName to newParentName
        								linkedMovedSuccess = true;
										updateLink(newParentName);
        						 }
        						 catch(Exception e)
        						 {
        								//do nothing
        						 }
        
        						 List assignedRolesList = getBirthRightAssignedRolesForIdentity(parentPersonaName);
        						 removeBirthRightRolesFromIdentity(parentPersonaName);
        						 if(linkedMovedSuccess)
        						 {
        							 //Check if the old identity from which links were moved has any links. 
        							 //If no links are there then mark it as protected, set protected=true, and if any links are there set protected = false
        							 boolean linksPresent = checkIfLinksExistOnIdentity(parentPersonaName);
        							 if(!linksPresent)
                       {
													setProtectedFlag = true;
                       }
                    	 addBirthRightRolesToIdentity(newParentName,assignedRolesList);
        						 }
        							
        
        						 //Username rename scenario logic
        						 Identity latestParentIden = context.getObjectByName(Identity.class,newParentName);

        						 Identity latestChildIden = context.getObjectByName(Identity.class,parentPersonaName);

        
                      //Write Audit records to IIQ.
                      String auditString1 = "Matching identity persona found in IIQ. Linking the incoming identity: "+newParentName + " to "+parentPersonaName;
        							String auditString2 = "";
                      if(wfcontext.getVariable("completerName")!=null)
        							{
                      	 auditString2 = "Decision taken by [Persona Joiner Workgroup] member: "+wfcontext.getVariable("completerName");
        							}
        							else if(wfcontext.getVariable("exactMatchFoundName")!=null && wfcontext.getVariable("exactMatchFoundName")!=void)
        							{
                      	 auditString2 = "Exact matching identity found on IIQ. Matching identity name: "+wfcontext.getVariable("exactMatchFoundName");
        							}
                      String auditString3 = "Based on persona parent child linking criteria, identity : "+parentPersonaName+ " is marked as child persona, and identity:"+newParentName+" is marked as the parent persona.";
                      writeAuditRecordToIIQ("PersonaJoiner" ,auditString1, auditString2,auditString3,newParentName,"Persona Joiner");
        
        						 String initialName = latestChildIden.getAttribute("initialName");
 										 boolean nameChangeNeededForNewParent = checkIfUserNameNeedsToBeChanged(newParentName);
        
        						 if(null!=initialName && nameChangeNeededForNewParent)
        						 {
        								//move usernames
        							  //samaccountname is on the latestChildIden name.
        								//initialname is on the latestChildIden
        								//incoming identity name is on the latestParentIden name
        								
        								//latestParentIden should be renamed using samaccountname (which is name of latestChildIden)
        								//intial name should be set as child identity name;
        								//incoming identity name to be stored as initialName on the latestParentIden 
        
        								String samName = latestChildIden.getName();
        
        								String initName = initialName;
        
        								String inIdenName = latestParentIden.getName();
        
        								latestChildIden.setName(initName);
        
						try
                        {
                          context.saveObject(latestChildIden);
                          context.commitTransaction();
                          //comment decache //context.decache(latestChildIden);
                        }
                        catch(Exception e)
                        {
                         //do nothing
                        }
                        
        
        								latestParentIden.setName(samName);
        								latestParentIden.setAttribute("initialName",inIdenName);
                        
						try
                        {
                          context.saveObject(latestParentIden);
                          context.commitTransaction();
                          //comment decache //context.decache(latestParentIden);
                        }
                        catch(Exception e)
                        {
                          //do nothing
                        }
                        
        								Identity latestChildIdentity = context.getObjectByName(Identity.class,initName);
        								Identity latestParentIdentity = context.getObjectByName(Identity.class,samName);
        								List chdPersonaList = latestParentIdentity.getAttribute("childPersonas");
                        List childNamesStr = getChildIdentities(chdPersonaList);
                        latestParentIdentity.setAttribute("childPersonaNames", childNamesStr);
        							
        								//Update primary identities details in child identities
     								 		updateParentPersonaAttributesInSecondaryIdentities(chdPersonaList,samName);
                        
						try
                        {
                          context.saveObject(latestParentIdentity);
                          context.commitTransaction();
                          //comment decache //context.decache(latestParentIdentity);
                        }
                        catch(Exception e)
                        {
                          //do nothing
                        }
                          
        							  workflow.put("modifiedName",samName);
        								
						if(null!=initialName)
                        {
                          auditString1 = "Based on the username move criteria, username moved from Child Identity to Parent Identity";
                          auditString2 = "Incoming identity (New Parent) username now is:"+ workflow.get("modifiedName") + " from earlier username: "+identityName;
                          auditString3 = "Matching identity (New Child) username now is:"+ initialName+ " from earlier username: "+parentPersonaName;
                          writeAuditRecordToIIQ("PersonaUsernameMove",auditString1, auditString2,auditString3,workflow.get("modifiedName"),"Persona Joiner");
                        }
        
						if(setProtectedFlag)
                        {
                            Identity tempChildIden = context.getObjectByName(Identity.class,initialName);
                            tempChildIden.setProtected(setProtectedFlag);
                            tempChildIden.setAttribute("samAccountName","");
                            context.saveObject(tempChildIden);
                            context.commitTransaction();
                            //comment decache //context.decache(tempChildIden);
                        }
					 }
					 else
                     {
						if(null!=newParentName)
						{
							workflow.put("incomingIdentityName",newParentName);
						}

						if(setProtectedFlag)
                        {
                            Identity tempChildIden = context.getObjectByName(Identity.class,latestChildIden.getName());
                            if(null!=tempChildIden)
							{
								tempChildIden.setProtected(setProtectedFlag);
								tempChildIden.setAttribute("samAccountName","");
								context.saveObject(tempChildIden);
								context.commitTransaction();
								//comment decache //context.decache(tempChildIden);
							}
                        }
                     }
        					
        							
        
            }//end else spl-linking
        
        }//End if

		import sailpoint.object.Identity;
          
         
          String newIdentityName = workflow.get("modifiedName");          
          
          String idenName = identityName;
          String incomingIdentityName = workflow.get("incomingIdentityName");
          if(null!=incomingIdentityName)
          {
            idenName = incomingIdentityName;
          }
          if(null!=newIdentityName && !newIdentityName.equalsIgnoreCase(idenName))
          {
            Identity tempIden = context.getObjectByName(Identity.class,newIdentityName);
        
            return newIdentityName;
          }
          else
          {
            Identity tempIden = context.getObjectByName(Identity.class,idenName);
          
            return idenName;
          }

        String newIdentityName = workflow.get("modifiedName"); 		
        if(null != newIdentityName && !newIdentityName.equalsIgnoreCase(identityName))
        {
	 Identity newIdentity = context.getObjectByName(Identity.class, newIdentityName);
		  if(null != newIdentity && Util.nullSafeCaseInsensitiveEq("Primary", newIdentity.getAttribute("personaType")))
          {
        	triggerWorkflow(newIdentityName, "Ascension-Workflow-Lifecycle-Rehire", trigger,flow);
		  }			
        }
        else
        {
	      Identity identity = context.getObjectByName(Identity.class, identityName);
		  if(null != identity && Util.nullSafeCaseInsensitiveEq("Primary", identity.getAttribute("personaType")))
          {
            triggerWorkflow(identityName, "Ascension-Workflow-Lifecycle-Rehire", trigger,flow);  
		  }			
        }

