import sailpoint.object.Identity; 
import sailpoint.object.Custom; 
import sailpoint.tools.Util; 

Identity identity = context.getObjectByName(Identity.class, identityName);
try
{
	String matchIdentityStr = identityModel.get("matchingIdentity");
	String matchStr = (matchIdentityStr.split(",")[0]).trim();
  identity.setAttribute("parentPersonaName",matchStr);
}
finally
{
  context.saveObject(identity);
  context.commitTransaction();
  //comment decache //context.decache(identity);
}

        import sailpoint.object.Identity; 
        import sailpoint.object.Custom; 
        import sailpoint.tools.Util; 
        
        Identity rejectedIdentity = context.getObjectByName(Identity.class,identityName);
        if(null!=rejectedIdentity)
        {
		try
        {
            rejectedIdentity.removeAttribute("parentPersonaName");
            rejectedIdentity.removeAttribute("parentPersonaSID");

            String sid = rejectedIdentity.getAttribute("internalId");
            if(sid==null || (null!=sid && sid.isEmpty()))
            {
				String internalIdentifier = generateNewInternalId();
                //Assign sailpoint identifier to the existing identity.
                rejectedIdentity.setAttribute("internalId",internalIdentifier);
                rejectedIdentity.setAttribute("personaType","Primary");
        				//Assign new username for the newly created cube.
        				boolean userNameChangeNeeded = checkIfUserNameNeedsToBeChanged(identityName);
        				if(userNameChangeNeeded)
        				{
                  String newUserName = generateUserName(rejectedIdentity.getFirstname(), rejectedIdentity.getLastname());
                  rejectedIdentity.setName(newUserName);
                  rejectedIdentity.setAttribute("initialName",identityName);
                  workflow.put("modifiedName",newUserName);
        				}
        
        				//Write Audit records to IIQ.
                String auditString1 = "No existing matching identity persona found in IIQ. Marking this identity as a net new and primary identity persona";
        				String auditString1a = "Identity Name: "+identityName+". Sailpoint Internal ID: "+internalIdentifier;
        				String auditString2 = "Decision taken by [Persona Joiner Workgroup] member: "+wfcontext.getVariable("completerName")+". "+auditString1a;
        				
        				String auditString3 = "";
        				
        				if(userNameChangeNeeded)
        			  {
                  auditString3 = "Based on the username change criteria, username has been changed from "+identityName +" to "+workflow.get("modifiedName");
        					writeAuditRecordToIIQ("PersonaUsernameChange" ,auditString3, "","",identityName,"Persona Joiner");
        				}
         				writeAuditRecordToIIQ("PersonaJoiner" ,auditString1, auditString2,auditString3,identityName,"Persona Joiner");
            }
        }catch(Exception ex){
        	throw new Exception("Identity Persona Decision - Net New Identity "+ex.getMessage());
        }
        finally
        {
          context.saveObject(rejectedIdentity);
          context.commitTransaction();
          //comment decache //context.decache(rejectedIdentity);
        }
	 }

        String newIdentityName = workflow.get("modifiedName");
		
		Map attributesMap = new HashMap();
        attributesMap.put("promoteAttributes",true);
        
        if(null!=newIdentityName && !newIdentityName.equalsIgnoreCase(identityName))
        {
				refreshIdentityCube(newIdentityName,attributesMap);
        		triggerWorkflow(newIdentityName,"Ascension-Workflow-Lifecycle-Joiner", trigger,flow);
        		workflow.put("incomingIdentityName",newIdentityName);
        }
        else
        {
				refreshIdentityCube(identityName,attributesMap);
        		triggerWorkflow(identityName,"Ascension-Workflow-Lifecycle-Joiner", trigger,flow);
        		workflow.put("incomingIdentityName",identityName);
        }

		import sailpoint.object.Identity;
          String newIdentityName = workflow.get("modifiedName"); //primary joiner usercase 
          String idenName = identityName;
          String incomingIdentityName = workflow.get("incomingIdentityName");
          if(null!=incomingIdentityName)
          {
            idenName = incomingIdentityName;
          }
          if(null!=newIdentityName && !newIdentityName.equalsIgnoreCase(idenName))
          {
            Identity tempIden = context.getObjectByName(Identity.class,newIdentityName);
            return newIdentityName;
          }
          else
          {
            Identity tempIden = context.getObjectByName(Identity.class,idenName);
            return idenName;
          }
